    for (let uid of users) {
        const userTweets = this.tweets.get(uid);
        if (userTweets && userTweets.length) {
            const index = userTweets.length - 1;
            heap.push({ ...userTweets[index], uid, index });
        }
    }

    heap.sort((a, b) => b.time - a.time);

    const result = [];

