    for (let i = n - 2; i >= 0; i--) {
        let j = i + 1;
        while (j < n && temperatures[j] <= temperatures[i]) {
            if (result[j] === 0) {
                j = n;
                break;
            }
            j += result[j];
        }
        if (j < n) {
            result[i] = j - i;
        }
    }

    return result;
};

