var removeDuplicateLetters = function(s) {
    const set = new Set(s);
    const uniqueCount = set.size;
    const results = [];

    function backtrack(index, path) {
        if (path.length > uniqueCount) return;
        if (index === s.length) {
            if (new Set(path).size === uniqueCount) {
                results.push(path);
            }
            return;
        }
        backtrack(index + 1, path);
        if (!path.includes(s[index])) {
            backtrack(index + 1, path + s[index]);
        }
    }

    backtrack(0, "");
    results.sort();
    return results[0];
};

var removeDuplicateLetters = function(s) {
    if (s.length === 0) return "";

    const lastIndex = {};
    for (let i = 0; i < s.length; i++) {
        lastIndex[s[i]] = i;
    }

    let pos = 0;
    for (let i = 0; i < s.length; i++) {
        if (s[i] < s[pos]) pos = i;
        if (i === lastIndex[s[i]]) break;
    }

    const char = s[pos];
    const remaining = s.slice(pos + 1).replace(new RegExp(char, 'g'), '');

    return char + removeDuplicateLetters(remaining);
};

var removeDuplicateLetters = function(s) {
    const freq = {};
    for (let ch of s) freq[ch] = (freq[ch] || 0) + 1;

    const stack = [];
    const seen = new Set();

    for (let ch of s) {
        freq[ch]--;
        if (seen.has(ch)) continue;

        while (stack.length && ch < stack[stack.length - 1] && freq[stack[stack.length - 1]] > 0) {
            seen.delete(stack.pop());
        }

        stack.push(ch);
        seen.add(ch);
    }

    return stack.join('');
};
